where.if:
AND (
	CAST(a.area_code AS text) = #{legalRegionCode}
	OR CAST((a.area_code * 1000 + coalesce(a.si_gun_gu_code, 0)) AS text) = #{legalRegionCode}
)

AND (
	CAST(a.content_type_id AS text) = #{category}
	OR upper(ct.content_type_name) = upper(#{category})
)

mapper.select:
SELECT a.content_id, a.title, NULLIF(concat_ws(' ', a.addr1, a.addr2), '') AS address, a.latitude, a.longitude, coalesce(image.public_url, a.first_image1, a.first_image2) AS thumbnail_url, coalesce(ct.content_type_name, 'UNKNOWN') AS category FROM tourism_source.attractions a LEFT JOIN tourism_source.contenttypes ct ON ct.content_type_id = a.content_type_id LEFT JOIN LATERAL ( SELECT ai.public_url FROM tourism_source.attraction_images ai WHERE ai.attraction_no = a.no AND ai.is_active = true ORDER BY ai.display_order ASC, ai.created_at ASC LIMIT 1 ) image ON true WHERE a.longitude BETWEEN #{bboxMinLng} AND #{bboxMaxLng} AND a.latitude BETWEEN #{bboxMinLat} AND #{bboxMaxLat}
AND ( CAST(a.content_type_id AS text) = #{category} OR upper(ct.content_type_name) = upper(#{category}) )
ORDER BY a.source_modified_at DESC NULLS LAST, a.imported_at DESC, a.no DESC LIMIT #{limit}
